const body = $input.first().json.body;
const action = (body.action || '').toLowerCase().trim();
const GH = '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';
const REPO = 'QuantumReti/ssd-command-centre';
const FILE = 'tasks.json';

async function getTasks() {
  const r = await fetch('https://api.github.com/repos/' + REPO + '/contents/' + FILE, {headers: {Authorization: 'Bearer ' + GH, 'User-Agent': 'mason-agent'}});
  if (!r.ok) return {tasks: [], sha: null};
  const d = await r.json();
  const content = JSON.parse(atob(d.content.replace(/\n/g, '')));
  return {...content, sha: d.sha};
}

async function saveTasks(data, sha) {
  const content = btoa(unescape(encodeURIComponent(JSON.stringify(data, null, 2))));
  await fetch('https://api.github.com/repos/' + REPO + '/contents/' + FILE, {
    method: 'PUT',
    headers: {Authorization: 'Bearer ' + GH, 'Content-Type': 'application/json', 'User-Agent': 'mason-agent'},
    body: JSON.stringify({message: 'Task: ' + action, content, sha})
  });
}

function genId() { return 'T' + Date.now().toString(36).toUpperCase(); }
function now() { return new Date().toISOString(); }

const {tasks, sha} = await getTasks();
let reply = '';

if (action === 'add' || action === 'new' || action === 'create') {
  const task = {id: genId(), title: body.title || 'Untitled', project: body.project || '', assigned: body.assigned || '', status: 'todo', priority: body.priority || 'medium', notes: body.notes || '', created: now(), updated: now()};
  tasks.push(task);
  await saveTasks({tasks, last_updated: now()}, sha);
  reply = 'Task added: [' + task.id + '] ' + task.title;
} else if (action === 'update' || action === 'status' || action === 'move') {
  const idx = tasks.findIndex(t => t.id === body.id);
  if (idx >= 0) {
    if (body.status) tasks[idx].status = body.status;
    if (body.title) tasks[idx].title = body.title;
    if (body.assigned) tasks[idx].assigned = body.assigned;
    if (body.priority) tasks[idx].priority = body.priority;
    tasks[idx].updated = now();
    await saveTasks({tasks, last_updated: now()}, sha);
    reply = 'Updated: [' + body.id + '] ' + (body.status || 'updated');
  } else { reply = 'Not found: ' + body.id; }
} else if (action === 'done' || action === 'complete') {
  const idx = tasks.findIndex(t => t.id === body.id);
  if (idx >= 0) { tasks[idx].status = 'done'; tasks[idx].updated = now(); await saveTasks({tasks, last_updated: now()}, sha); reply = 'Done: [' + body.id + '] ' + tasks[idx].title; }
  else { reply = 'Not found: ' + body.id; }
} else if (action === 'delete' || action === 'remove') {
  const idx = tasks.findIndex(t => t.id === body.id);
  if (idx >= 0) { const r = tasks.splice(idx, 1)[0]; await saveTasks({tasks, last_updated: now()}, sha); reply = 'Removed: ' + r.title; }
  else { reply = 'Not found: ' + body.id; }
} else if (action === 'list') {
  const a = tasks.filter(t => t.status !== 'done');
  reply = a.length + ' active tasks:\n' + a.map(t => '[' + t.id + '] ' + t.status.toUpperCase() + ' - ' + t.title + (t.assigned ? ' (' + t.assigned + ')' : '')).join('\n');
} else if (action === 'get' || action === '') {
  return [{json: {tasks, last_updated: new Date().toISOString()}}];
} else { reply = 'Unknown action: ' + action; }

return [{json: {success: true, reply, tasks}}];
